// Simulador de envio WhatsApp
const dados = $input.item.json;

// Simular envio (95% sucesso)
const sucessoEnvio = Math.random() > 0.05;

const resultado = {
  ...dados,
  status_envio: sucessoEnvio ? 'ENVIADO' : 'ERRO',
  message_id: 'MSG_' + Date.now(),
  delivery_status: sucessoEnvio ? 'delivered' : 'failed',
  cost_estimate: 0.05, // R$ 0,05 por mensagem
  academia: 'Full Force Academia',
  cidade: 'Matupá-MT',
  simulado: true
};

// Logs detalhados
console.log('📱 [WHATSAPP SIMULATOR] Enviando mensagem:');
console.log('📞 Para:', dados.phoneNumber);
console.log('👤 Nome:', dados.recipientName);
console.log('💬 Mensagem:', dados.messageText.substring(0, 50) + '...');
console.log('✅ Status:', resultado.status_envio);
console.log('🆔 Message ID:', resultado.message_id);

if (sucessoEnvio) {
  console.log('🎯 [SUCESSO] Mensagem enviada com sucesso!');
} else {
  console.log('❌ [ERRO] Falha no envio da mensagem');
}

return resultado;

